mapper.select:
SELECT
/* 금일 작업 건수 */ ( SELECT COUNT(*) FROM work w WHERE w.work_usage = 'Y' AND TRUNC(w.work_date) = TRUNC(SYSDATE + (9/24)) ) AS "todayWorkCnt",
/* 금일 작업 완료 건수 */ ( SELECT COUNT(*) FROM work w WHERE w.work_usage = 'Y' AND TRUNC(w.work_date) = TRUNC(SYSDATE + (9/24)) AND w.work_status = 30 ) AS "todayDoneWorkCnt",
/* 금일 품질 검사 건수 */ ( SELECT COUNT(*) FROM qc q WHERE q.qc_usage = 'Y' AND TRUNC(q.qc_date) = TRUNC(SYSDATE + (9/24)) ) AS "todayQcCnt",
/* 금일 불량률 */ ( SELECT NVL(ROUND( SUM(NVL(dl.defect_qty, 0)) / NULLIF(SUM(NVL(q.qc_qty, 0)), 0) * 100, 2 ), 0) FROM qc q LEFT JOIN ( SELECT dlog_qcid, SUM(NVL(dlog_qty, 0)) AS defect_qty FROM def_log GROUP BY dlog_qcid ) dl ON q.qc_id = dl.dlog_qcid WHERE q.qc_usage = 'Y' AND q.qc_qty IS NOT NULL AND q.qc_qty > 0 AND TRUNC(q.qc_date) = TRUNC(SYSDATE + (9/24)) ) AS "todayFailRate"
FROM dual

SELECT /* 금일 작업 전체 건수 */ ( SELECT COUNT(*) FROM work w WHERE w.work_usage = 'Y' AND TRUNC(w.work_date) = TRUNC(SYSDATE + (9/24)) ) AS "todayWorkCnt",
/* 금일 작업 완료 건수 */ ( SELECT COUNT(*) FROM work w WHERE w.work_usage = 'Y' AND TRUNC(w.work_date) = TRUNC(SYSDATE + (9/24)) AND w.work_status = 30 ) AS "todayDoneWorkCnt",
/* 금일 작업 진행률 */ ( SELECT NVL(ROUND( SUM(CASE WHEN w.work_status = 30 THEN 1 ELSE 0 END) / NULLIF(COUNT(*), 0) * 100, 0 ), 0) FROM work w WHERE w.work_usage = 'Y' AND TRUNC(w.work_date) = TRUNC(SYSDATE + (9/24)) ) AS "todayWorkProgressRate",
/* 금일 품질검사 전체 건수 */ ( SELECT COUNT(*) FROM qc q WHERE q.qc_usage = 'Y' AND TRUNC(q.qc_date) = TRUNC(SYSDATE + (9/24)) ) AS "todayQcCnt",
/* 금일 품질검사 완료 건수 */ ( SELECT COUNT(*) FROM qc q WHERE q.qc_usage = 'Y' AND TRUNC(q.qc_date) = TRUNC(SYSDATE + (9/24)) AND q.qc_status = 30 ) AS "todayDoneQcCnt",
/* 금일 품질검사 진행률 */ ( SELECT NVL(ROUND( SUM(CASE WHEN q.qc_status = 30 THEN 1 ELSE 0 END) / NULLIF(COUNT(*), 0) * 100, 0 ), 0) FROM qc q WHERE q.qc_usage = 'Y' AND TRUNC(q.qc_date) = TRUNC(SYSDATE + (9/24)) ) AS "todayQcProgressRate"
FROM dual
